package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import com.google.common.collect.ImmutableSet;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.Collection;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.BESLAG_OP_LOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.BESLAG_MAAND_PERSOONSFISCALITEIT_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.BESLAG_MAAND_RESULTATEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_INHOUDING_BESLAG_OP_LOON;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_INHOUDING_ONDERHOUDSGELD;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRE_BEREKENING_CONTEXT_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.LOONBESLAG_IBAN;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.LOONBESLAG_NAAM_SCHULDEISER;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey.LOONBESLAG_OPMERKING;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;

public class BerekenBeslagOpLoon extends AbstractRekenCommand {

    public static final int CODE_VRIJWILLIGER = 1419;
    public static final int ONDERHOUDSGELD_BLO_CODE = 5102;
    public static final int BESLAG_OP_LOON_CODE = 5101;
    public static final int VOORDEEL_IN_NATURA_CODE = 5701;
    private static final Set<Integer> EXTENSIES_BLO_WETTELIJKE_REGELING = ImmutableSet.of(1, 51);
    private static final LocalDate DATUM_BLO_KINDERLAST = new LocalDate(2003, 7, 1);
    private static final LocalDate DATUM_VERHOGING_GRENS_AANTAL = new LocalDate(2001, 1, 1);
    private static final int GRENS_BLO_AANTAL_OUD = 3;
    private static final int GRENS_BLO_AANTAL = 4;
    private static final Konstanten[] ENUMS_GRENS_BLO =
            {Konstanten.KST_BLO_GR1, Konstanten.KST_BLO_GR2, Konstanten.KST_BLO_GR3, Konstanten.KST_BLO_GR4};
    private static final Konstanten[] ENUMS_PERCENTAGE_BLO =
            {Konstanten.KST_BLO_PCT1, Konstanten.KST_BLO_PCT2, Konstanten.KST_BLO_PCT3, Konstanten.KST_BLO_PCT4, Konstanten.KST_BLO_PCT5};
    private ConstantManager constantManager;
    private Money[] grensBlo = new Money[5];
    private BigDecimal[] percentageBlo = new BigDecimal[5];

    public BerekenBeslagOpLoon(ConstantManager constantManager, NlpGlobalService globalService) {
        this.constantManager = constantManager;
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        BeslagOpLoonInfo onderhoudsgeld = mainContext.getUnchecked(PERSOON_INHOUDING_ONDERHOUDSGELD);
        BeslagOpLoonInfo beslagOpLoon = mainContext.getUnchecked(PERSOON_INHOUDING_BESLAG_OP_LOON);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        List<BloItem> items = new ArrayList<>();
        if (beslagOpLoon != null || onderhoudsgeld != null) {
            List<RekenHoofd> beslagMaandResultaten = mainContext.getUnchecked(BESLAG_MAAND_RESULTATEN_KEY);
            LoonCodeManager loonCodeManager = mainContext.getUnchecked(LOONCODE_MANAGER_KEY);
            BeslagMaandGegevens gegevens = analyseerBeslagMaandResultaten(beslagMaandResultaten, rekenTijd, loonCodeManager);
            Money basisBloHuidigeMaand = analyseerHuidigeMaand(mainContext);
            Money basisBloAndereBeslagMaand = analyseerVorigeResultatenAndereBeslagMaanden(mainContext, rekenTijd);
            basisBloHuidigeMaand = basisBloHuidigeMaand.subtract(basisBloAndereBeslagMaand).max(Money.ZERO);
            gegevens.bloBasis = gegevens.bloBasis.add(basisBloHuidigeMaand);
            Money bedragOhg = Money.ZERO;
            if (onderhoudsgeld != null) {
                bedragOhg = onderhoudsgeld.getMaandBedrag().subtract(gegevens.prevOhgBedrag).min(gegevens.bloBasis);
            }
            Money bedragBlo = Money.ZERO;
            if (beslagOpLoon != null) {
                Money basisBlo = gegevens.bloBasis;
                basisBlo = basisBlo.subtract(bedragOhg);

                PersoonsFiscaliteit beslagPersoonsFiscaliteit = mainContext.getUnchecked(BESLAG_MAAND_PERSOONSFISCALITEIT_KEY);
                bedragBlo = vormBedragBlo(beslagOpLoon, beslagPersoonsFiscaliteit, basisBlo, rekenTijd);
                bedragBlo = bedragBlo.subtract(gegevens.prevBloBedrag).min(basisBlo).max(Money.ZERO);
            }
            items.addAll(verdeelBeslagOpLoon(mainContext, onderhoudsgeld, bedragOhg, beslagOpLoon, bedragBlo, rekenTijd.beslagDatum));
        }

        RekenContext preBerekeningContext = mainContext.getUnchecked(PRE_BEREKENING_CONTEXT_KEY);
        LoonElementManager prevManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        items.addAll(bepaalBestaandeBloItems(prevManager));
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (BloItem item : items) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(item.opdracht);
            Opper opper = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
            LoonElement element = manager.getLoonElement(item.looncode, opper, item.beslagDatum, null);
            if (element == null) {
                element = new LoonElement(item.looncode);
                element.setBeslagDatum(item.beslagDatum);
                manager.addLoonElement(element, opper);
            }
            element.addToProperty(NETTO_KEY, item.bedrag);
            element.putProperty(LOONBESLAG_NAAM_SCHULDEISER, item.beneficiary);
            element.putProperty(LOONBESLAG_IBAN, item.iban);
            element.putProperty(LOONBESLAG_OPMERKING, item.opmerking);
        }

        return CONTINUE_PROCESSING;
    }

    private List<BloItem> bepaalBestaandeBloItems(LoonElementManager prevManager) {
        List<BloItem> items = new ArrayList<>();

        Collection<LoonElement> loonElementen = prevManager.getPersoonsElementen();
        for (LoonElement element : loonElementen) {
            AardKodeExtensie looncode = element.getAardKodeExtensie();
            if (looncode.behoortTotGroep(BESLAG_OP_LOON_KEY)) {
                Money bedrag = element.getPropertyMoney(NETTO_KEY);
                String beneficiary = element.getPropertyUnchecked(LOONBESLAG_NAAM_SCHULDEISER);
                String iban = element.getPropertyUnchecked(LOONBESLAG_IBAN);
                String opmerking = element.getPropertyUnchecked(LOONBESLAG_OPMERKING);

                BloItem item = new BloItem(looncode, element.getOpdracht(), element.getBeslagDatum(), bedrag, beneficiary, iban, null, opmerking);
                items.add(item);
            }
        }
        return items;
    }

    private Money analyseerHuidigeMaand(RekenContext context) {
        Money bloBasis = Money.ZERO;
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        LoonCodeManager loonCodeManager = context.getUnchecked(LOONCODE_MANAGER_KEY);
        for (LoonElement element : manager.getPersoonsElementen()) {
            AardKodeExtensie looncode = loonCodeManager.getById(element.getAardKodeExtensie().getId());

            boolean isGeenVrijwilliger = !looncode.getCode().equals(CODE_VRIJWILLIGER);
            boolean isGeenInhouding = !looncode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode());
            if ((isGeenInhouding || looncode.getCode() == VOORDEEL_IN_NATURA_CODE) && looncode.getCode() != BESLAG_OP_LOON_CODE && isGeenVrijwilliger) {
                bloBasis = bloBasis.add(element.getPropertyMoney(NETTO_KEY));
            }
        }
        return bloBasis;
    }

    private Money analyseerVorigeResultatenAndereBeslagMaanden(RekenContext context, RekenTijd rekenTijd) {
        Money bloBasis = Money.ZERO;
        PersoonsDataManager datamanager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        LoonCodeManager loonCodeManager = context.getUnchecked(LOONCODE_MANAGER_KEY);
        List<RekenHoofd> bestaandeRekenResultaten = datamanager.getBestaandeRekenResultaten(rekenTijd.beginDatum);
        LocalDate beslagDatum = rekenTijd.beslagDatum.dayOfMonth().withMinimumValue();
        for (RekenHoofd hoofd : bestaandeRekenResultaten) {
            boolean isBeslagMaand = hoofd.getBeslagDatum().dayOfMonth().withMinimumValue().equals(beslagDatum);
            if (hoofd.getRnummer() != null && !isBeslagMaand) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    AardKodeExtensie looncode = loonCodeManager.getById(lijn.getAardKodeExtensie().getId());

                    boolean isGeenVrijwilliger = !looncode.getCode().equals(CODE_VRIJWILLIGER);
                    boolean isGeenInhouding = !looncode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode());
                    if ((isGeenInhouding || looncode.getCode() == VOORDEEL_IN_NATURA_CODE) && looncode.getCode() != BESLAG_OP_LOON_CODE && isGeenVrijwilliger) {
                        for (RekenBedrag bedrag : lijn.getRekenBedragen()) {
                            if (bedrag.getBedragType() == RekenBedragType.NETTO) {
                                bloBasis = bloBasis.add(bedrag.getBedrag());
                            }
                        }
                    }
                }
            }
        }
        return bloBasis;
    }

    private BeslagMaandGegevens analyseerBeslagMaandResultaten(
            List<RekenHoofd> beslagMaandResultaten, RekenTijd rekenTijd,
            LoonCodeManager loonCodeManager) {
        BeslagMaandGegevens gegevens = new BeslagMaandGegevens();
        for (RekenHoofd hoofd : beslagMaandResultaten) {
            boolean isHuidigeMaand = hoofd.getBeginDatum().equals(rekenTijd.beginDatum);
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                AardKodeExtensie looncode = loonCodeManager.getById(lijn.getAardKodeExtensie().getId());

                boolean isGeenVrijwilliger = !looncode.getCode().equals(CODE_VRIJWILLIGER);
                boolean isBeslagOpLoon = looncode.behoortTotGroep(BESLAG_OP_LOON_KEY);
                boolean isGeenInhouding = !looncode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode());
                if ((isGeenInhouding || isBeslagOpLoon || looncode.getCode() == VOORDEEL_IN_NATURA_CODE) && isGeenVrijwilliger) {
                    for (RekenBedrag bedrag : lijn.getRekenBedragen()) {
                        if (bedrag.getBedragType() == RekenBedragType.NETTO) {
                            if (looncode.getCode() == ONDERHOUDSGELD_BLO_CODE && isBeslagOpLoon) {
                                gegevens.prevOhgBedrag = gegevens.prevOhgBedrag.add(bedrag.getBedrag().negate());
                            } else if (looncode.getCode() == BESLAG_OP_LOON_CODE && isBeslagOpLoon) {
                                gegevens.prevBloBedrag = gegevens.prevBloBedrag.add(bedrag.getBedrag().negate());
                            }

                            if (!isHuidigeMaand && looncode.getCode() != BESLAG_OP_LOON_CODE) {
                                gegevens.bloBasis = gegevens.bloBasis.add(bedrag.getBedrag());
                            }
                        }
                    }
                }
            }
        }
        return gegevens;
    }

    private List<BloItem> verdeelBeslagOpLoon(
            RekenContext context, BeslagOpLoonInfo onderhoudsgeld, Money bedragOhg, BeslagOpLoonInfo beslagOpLoon,
            Money bedragBlo, LocalDate beslagDatum) {
        Persoon persoon = context.getUnchecked(PERSOON_KEY);
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        MoneyMap<Opdracht> opdrachtToNetto = new HashMoneyMap<>();
        Money totaalNetto = Money.ZERO;
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
            Money netto = Money.ZERO;
            for (LoonElement element : opdrachtElementen) {
                AardKodeExtensie looncode = element.getAardKodeExtensie();

                boolean isGeenVrijwilliger = !looncode.getCode().equals(CODE_VRIJWILLIGER);
                if ((!looncode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode()) || looncode.getCode() == VOORDEEL_IN_NATURA_CODE) && isGeenVrijwilliger) {
                    netto = netto.add(element.getPropertyMoney(NETTO_KEY));
                }
            }
            totaalNetto = totaalNetto.add(netto);
            opdrachtToNetto.put(opdracht, netto);
        }
        List<BloItem> items;
        items = verdeelBeslagOpLoon2(persoon, opdrachtToNetto, totaalNetto, onderhoudsgeld, bedragOhg, beslagDatum);
        items.addAll(verdeelBeslagOpLoon2(persoon, opdrachtToNetto, totaalNetto, beslagOpLoon, bedragBlo, beslagDatum));
        return items;
    }

    private List<BloItem> verdeelBeslagOpLoon2(
            Persoon persoon, MoneyMap<Opdracht> opdrachtToNetto, Money totaalNetto,
            BeslagOpLoonInfo persoonsInhouding, Money bedrag, LocalDate beslagDatum) {
        List<BloItem> items = new ArrayList<>();
        if (persoonsInhouding != null && bedrag.signum() != 0) {
            Money carryover = Money.ZERO;
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                Money netto = opdrachtToNetto.get(opdracht);
                if (netto.signum() != 0) {
                    BigDecimal verhouding;
                    if (totaalNetto.signum() != 0) {
                        verhouding = netto.divide(totaalNetto);
                    } else {
                        verhouding = BigDecimal.ONE.divide(BigDecimal.valueOf(persoon.getOpdrachten().size()), RoundingMode.HALF_UP);
                    }
                    Money elementBedrag = bedrag.multiply(verhouding).add(carryover);
                    carryover = elementBedrag.subtract(elementBedrag.round(2));
                    elementBedrag = elementBedrag.round(2).negate();

                    BloItem item = new BloItem(persoonsInhouding, opdracht, beslagDatum, elementBedrag);
                    items.add(item);
                }
            }
        }
        return items;
    }

    private Money vormBedragBlo(BeslagOpLoonInfo beslagOpLoon, PersoonsFiscaliteit persoonsFiscaliteit, Money bloBasis, RekenTijd rekenTijd) {
        Money bloBedrag = Money.ZERO;
        if (EXTENSIES_BLO_WETTELIJKE_REGELING.contains(beslagOpLoon.getLoonCode().getExtensie())) {
            loadConstantsBlo(rekenTijd);
            Money kinderlastBlo = Money.ZERO;
            if (rekenTijd.beslagDatum.compareTo(DATUM_BLO_KINDERLAST) >= 0) {
                Constant kinderlastBloCst =
                        constantManager.getByCodeDatum(Konstanten.KST_BLO_KINDERLAST, rekenTijd.beslagDatum.dayOfMonth().withMaximumValue());
                if (kinderlastBloCst != null) {
                    kinderlastBlo = kinderlastBloCst.getMoney().multiply(persoonsFiscaliteit.getKinderlastLoonBeslag());
                }
            }
            int aantalGrenzen = rekenTijd.beslagDatum.compareTo(DATUM_VERHOGING_GRENS_AANTAL) < 0 ? GRENS_BLO_AANTAL_OUD : GRENS_BLO_AANTAL;

            int grensnr = 0;
            while ((grensnr < aantalGrenzen) && bloBasis.compareTo(grensBlo[grensnr + 1]) > 0) {
                grensnr++;
            }
            for (int index = 0; index < grensnr; index++) {
                bloBedrag = bloBedrag.add(grensBlo[index + 1].subtract(grensBlo[index]).multiply(percentageBlo[index]));
            }
            bloBedrag = bloBedrag.add(bloBasis.subtract(grensBlo[grensnr]).multiply(percentageBlo[grensnr]));
            bloBedrag = bloBedrag.subtract(kinderlastBlo);
            if (bloBedrag.compareTo(beslagOpLoon.getTotaalBedrag()) > 0) {
                bloBedrag = beslagOpLoon.getTotaalBedrag();
            }
        } else {
            bloBedrag = beslagOpLoon.getMaandBedrag();
        }
        bloBedrag = bloBedrag.round(2);
        return bloBedrag;
    }

    private void loadConstantsBlo(RekenTijd rekenTijd) {
        grensBlo[0] = Money.ZERO;
        for (int index = 0; index < ENUMS_GRENS_BLO.length; index++) {
            grensBlo[index + 1] = constantManager.getByCodeDatum(ENUMS_GRENS_BLO[index], rekenTijd.beslagDatum.dayOfMonth().withMaximumValue()).getMoney();
        }

        for (int index = 0; index < ENUMS_PERCENTAGE_BLO.length; index++) {
            percentageBlo[index] = constantManager.getByCodeDatum(ENUMS_PERCENTAGE_BLO[index], rekenTijd.beslagDatum.dayOfMonth().withMaximumValue()).getProcentFactor();
        }

    }

    private static class BloItem {

        private AardKodeExtensie looncode;
        private Opdracht opdracht;
        private LocalDate beslagDatum;
        private Money bedrag;
        private String beneficiary;
        private String iban;
        private String bic;
        private String opmerking;

        public BloItem(BeslagOpLoonInfo info, Opdracht opdracht, LocalDate beslagDatum, Money bedrag) {
            this(info.getLoonCode(), opdracht, beslagDatum, bedrag, info.getBeneficiary(), info.getIban(), info.getBic(), info.getOpmerking());
        }

        public BloItem(
                AardKodeExtensie looncode, Opdracht opdracht, LocalDate beslagDatum, Money bedrag, String beneficiary, String iban, String bic,
                String opmerking) {
            this.looncode = looncode;
            this.beslagDatum = beslagDatum;
            this.bedrag = bedrag;
            this.opdracht = opdracht;

            this.beneficiary = beneficiary;
            this.iban = iban;
            this.bic = bic;
            this.opmerking = opmerking;
        }
    }

    private static class BeslagMaandGegevens {

        private Money prevOhgBedrag = Money.ZERO;
        private Money prevBloBedrag = Money.ZERO;
        //blo basis niet huidige maand
        private Money bloBasis = Money.ZERO;
    }

}
